    16→package org.pkl.parser;
    17→
    18→import java.util.ArrayDeque;
    19→import java.util.Deque;
    20→import org.pkl.parser.util.ErrorMessages;
    21→
    22→public class Lexer {
    23→
    24→  private final char[] source;
    25→  private final int size;
    26→  protected int cursor = 0;
    27→  protected int sCursor = 0;
    28→  private char lookahead;
    29→  private State state = State.DEFAULT;
    30→  private final Deque<InterpolationScope> interpolationStack = new ArrayDeque<>();
    31→  private boolean stringEnded = false;
    32→  private boolean isEscape = false;
    33→  // how many newlines exist between two subsequent tokens
    34→  protected int newLinesBetween = 0;
    35→
    36→  private static final char EOF = Short.MAX_VALUE;
    37→
    38→  public Lexer(String input) {
    39→    source = input.toCharArray();
    40→    size = source.length;
    41→    if (size > 0) {
    42→      lookahead = source[cursor];
    43→    } else {
    44→      lookahead = EOF;
    45→    }
    46→  }
    47→
    48→  // The span of the last lexed token
    49→  public Span span() {
    50→    return new Span(sCursor, cursor - sCursor);
    51→  }
    52→
    53→  // The text of the last lexed token
    54→  public String text() {
    55→    return new String(source, sCursor, cursor - sCursor);
    56→  }
    57→
    58→  public char[] getSource() {
    59→    return source;
    60→  }
    61→
    62→  public String textFor(int offset, int size) {
    63→    return new String(source, offset, size);
    64→  }
    65→
    66→  public Token next() {
    67→    sCursor = cursor;
    68→    newLinesBetween = 0;
    69→    return switch (state) {
    70→      case DEFAULT -> nextDefault();
    71→      case STRING -> nextString();
    72→    };
    73→  }
    74→
    75→  private Token nextDefault() {
    76→    var ch = nextChar();
    77→    // ignore spaces
    78→    while (ch == ' ' || ch == '\n' || ch == '\t' || ch == '\f' || ch == '\r') {
    79→      sCursor = cursor;
    80→      if (ch == '\n') {
    81→        newLinesBetween++;
    82→      }
    83→      ch = nextChar();
    84→    }
    85→    return switch (ch) {
    86→      case EOF -> {
    87→        // when EOF is reached we overshot the span
    88→        cursor--;
    89→        yield Token.EOF;
    90→      }
    91→      case ';' -> Token.SEMICOLON;
    92→      case '(' -> {
    93→        var scope = interpolationStack.peek();
    94→        if (scope != null) {
    95→          scope.parens++;
    96→        }
    97→        yield Token.LPAREN;
    98→      }
    99→      case ')' -> {
   100→        var scope = interpolationStack.peek();
   101→        if (scope != null) {
   102→          scope.parens--;
   103→          if (scope.parens <= 0) {
   104→            // interpolation is over. Back to string
   105→            state = State.STRING;
   106→          }
   107→        }
   108→        yield Token.RPAREN;
   109→      }
   110→      case '{' -> Token.LBRACE;
   111→      case '}' -> Token.RBRACE;
   112→      case ',' -> Token.COMMA;
   113→      case '@' -> Token.AT;
   114→      case ':' -> Token.COLON;
   115→      case '+' -> Token.PLUS;
   116→      case '%' -> Token.MOD;
   117→      case '[' -> {
   118→        if (lookahead == '[') {
   119→          nextChar();
   120→          yield Token.LPRED;
   121→        } else yield Token.LBRACK;
   122→      }
   123→      case ']' -> Token.RBRACK;
   124→      case '=' -> {
   125→        if (lookahead == '=') {
   126→          nextChar();
   127→          yield Token.EQUAL;
   128→        } else yield Token.ASSIGN;
   129→      }
   130→      case '>' -> {
   131→        if (lookahead == '=') {
   132→          nextChar();
   133→          yield Token.GTE;
   134→        } else yield Token.GT;
   135→      }
   136→      case '<' -> {
   137→        if (lookahead == '=') {
   138→          nextChar();
   139→          yield Token.LTE;
   140→        } else yield Token.LT;
   141→      }
   142→      case '-' -> {
   143→        if (lookahead == '>') {
   144→          nextChar();
   145→          yield Token.ARROW;
   146→        } else yield Token.MINUS;
   147→      }
   148→      case '!' -> {
   149→        if (lookahead == '!') {
   150→          nextChar();
   151→          yield Token.NON_NULL;
   152→        } else if (lookahead == '=') {
   153→          nextChar();
   154→          yield Token.NOT_EQUAL;
   155→        } else yield Token.NOT;
   156→      }
   157→      case '?' -> {
   158→        if (lookahead == '.') {
   159→          nextChar();
   160→          yield Token.QDOT;
   161→        } else if (lookahead == '?') {
   162→          nextChar();
   163→          yield Token.COALESCE;
   164→        } else yield Token.QUESTION;
   165→      }
   166→      case '&' -> {
   167→        if (lookahead == '&') {
   168→          nextChar();
   169→          yield Token.AND;
   170→        } else {
   171→          throw unexpectedChar(ch, "&&");
   172→        }
   173→      }
   174→      case '|' -> {
   175→        if (lookahead == '>') {
   176→          nextChar();
   177→          yield Token.PIPE;
   178→        } else if (lookahead == '|') {
   179→          nextChar();
   180→          yield Token.OR;
   181→        } else {
   182→          yield Token.UNION;
   183→        }
   184→      }
   185→      case '*' -> {
   186→        if (lookahead == '*') {
   187→          nextChar();
   188→          yield Token.POW;
   189→        } else yield Token.STAR;
   190→      }
   191→      case '~' -> {
   192→        if (lookahead == '/') {
   193→          nextChar();
   194→          yield Token.INT_DIV;
   195→        } else {
   196→          throw unexpectedChar(ch, "~/");
   197→        }
   198→      }
   199→      case '.' -> {
   200→        if (lookahead == '.') {
   201→          nextChar();
   202→          if (lookahead == '.') {
   203→            nextChar();
   204→            if (lookahead == '?') {
   205→              nextChar();
   206→              yield Token.QSPREAD;
   207→            } else {
   208→              yield Token.SPREAD;
   209→            }
   210→          } else {
   211→            throw unexpectedChar("..", ".", "...", "...?");
   212→          }
   213→        } else if (lookahead >= 48 && lookahead <= 57) {
   214→          yield lexNumber(ch);
   215→        } else {
   216→          yield Token.DOT;
   217→        }
   218→      }
   219→      case '`' -> {
   220→        lexQuotedIdentifier();
   221→        yield Token.IDENTIFIER;
   222→      }
   223→      case '/' -> lexSlash();
   224→      case '"' -> lexStringStart(0);
   225→      case '#' -> {
   226→        if (lookahead == '!') {
   227→          yield lexShebang();
   228→        } else {
   229→          yield lexStringStartPounds();
   230→        }
   231→      }
   232→      default -> {
   233→        if (Character.isDigit(ch)) {
   234→          yield lexNumber(ch);
   235→        } else if (isIdentifierStart(ch)) {
   236→          yield lexIdentifier();
   237→        } else throw lexError(ErrorMessages.create("invalidCharacter", ch), cursor - 1, 1);
   238→      }
   239→    };
   240→  }
   241→
   242→  private Token nextString() {
   243→    var scope = interpolationStack.getFirst();
   244→    if (stringEnded) {
   245→      lexStringEnd(scope);
   246→      stringEnded = false;
   247→      interpolationStack.pop();
   248→      state = State.DEFAULT;
   249→      return Token.STRING_END;
   250→    }
   251→    if (lookahead == EOF) return Token.EOF;
   252→    if (isEscape) {
   253→      isEscape = false;
   254→      // consume the `\#*`
   255→      for (var i = 0; i < scope.pounds + 1; i++) {
   256→        nextChar();
   257→      }
   258→      return lexEscape();
   259→    }
   260→    if (scope.quotes == 1) {
   261→      lexString(scope.pounds);
   262→    } else {
   263→      if (lookahead == '\r') {
   264→        nextChar();
   265→        if (lookahead == '\n') {
   266→          nextChar();
   267→        }
   268→        return Token.STRING_NEWLINE;
   269→      }
   270→      if (lookahead == '\n') {
   271→        nextChar();
   272→        return Token.STRING_NEWLINE;
   273→      }
   274→      lexMultiString(scope.pounds);
   275→    }
   276→    return Token.STRING_PART;
   277→  }
   278→
   279→  private Token lexStringStartPounds() {
   280→    int pounds = 1;
   281→    while (lookahead == '#') {
   282→      nextChar();
   283→      pounds++;
   284→    }
   285→    if (lookahead == EOF) {
   286→      throw lexError(ErrorMessages.create("unexpectedEndOfFile"), span());
   287→    }
   288→    if (lookahead != '"') {
   289→      throw unexpectedChar(lookahead, "\"");
   290→    }
   291→    nextChar();
   292→    return lexStringStart(pounds);
   293→  }
   294→
   295→  private Token lexStringStart(int pounds) {
   296→    var quotes = 1;
   297→    if (lookahead == '"') {
   298→      nextChar();
   299→      if (lookahead == '"') {
   300→        nextChar();
   301→        quotes = 3;
   302→      } else {
   303→        backup();
   304→      }
   305→    }
   306→    state = State.STRING;
   307→    interpolationStack.push(new InterpolationScope(quotes, pounds));
   308→    stringEnded = false;
   309→    if (quotes == 1) return Token.STRING_START;
   310→    return Token.STRING_MULTI_START;
   311→  }
   312→
   313→  private void lexStringEnd(InterpolationScope scope) {
   314→    // don't actually need to check it here
   315→    for (var i = 0; i < scope.quotes + scope.pounds; i++) {
   316→      nextChar();
   317→    }
   318→  }
   319→
   320→  private void lexString(int pounds) {
   321→    var poundsInARow = 0;
   322→    var foundQuote = false;
   323→    var foundBackslash = false;
   324→    while (lookahead != EOF) {
   325→      var ch = nextChar();
   326→      switch (ch) {
   327→        case '\n', '\r' ->
   328→            throw lexError(
   329→                ErrorMessages.create("missingDelimiter", "\"" + "#".repeat(pounds)), cursor - 1, 1);
   330→        case '"' -> {
   331→          if (pounds == 0) {
   332→            backup();
   333→            stringEnded = true;
   334→            return;
   335→          }
   336→          foundQuote = true;
   337→          foundBackslash = false;
   338→          poundsInARow = 0;
   339→        }
   340→        case '\\' -> {
   341→          foundQuote = false;
   342→          foundBackslash = true;
   343→          poundsInARow = 0;
   344→          if (pounds == poundsInARow) {
   345→            backup(pounds + 1);
   346→            isEscape = true;
   347→            return;
   348→          }
   349→        }
   350→        case '#' -> {
   351→          poundsInARow++;
   352→          if (foundQuote && (pounds == poundsInARow)) {
   353→            backup(pounds + 1);
   354→            stringEnded = true;
   355→            return;
   356→          }
   357→          if (foundBackslash && pounds == poundsInARow) {
   358→            backup(pounds + 1);
   359→            isEscape = true;
   360→            return;
   361→          }
   362→        }
   363→        default -> {
   364→          foundQuote = false;
   365→          foundBackslash = false;
   366→          poundsInARow = 0;
   367→        }
   368→      }
   369→    }
   370→  }
   371→
   372→  private void lexMultiString(int pounds) {
   373→    var poundsInARow = 0;
   374→    var quotesInARow = 0;
   375→    var foundBackslash = false;
   376→    while (lookahead != EOF && lookahead != '\n' && lookahead != '\r') {
   377→      var ch = nextChar();
   378→      switch (ch) {
   379→        case '"' -> {
   380→          quotesInARow++;
   381→          if (quotesInARow == 3 && pounds == 0) {
   382→            backup(3);
   383→            stringEnded = true;
   384→            return;
   385→          }
   386→          poundsInARow = 0;
   387→          foundBackslash = false;
   388→        }
   389→        case '\\' -> {
   390→          quotesInARow = 0;
   391→          poundsInARow = 0;
   392→          foundBackslash = true;
   393→          if (pounds == poundsInARow) {
   394→            backup(pounds + 1);
   395→            isEscape = true;
   396→            return;
   397→          }
   398→        }
   399→        case '#' -> {
   400→          poundsInARow++;
   401→          if (quotesInARow == 3 && pounds == poundsInARow) {
   402→            backup(pounds + 3);
   403→            stringEnded = true;
   404→            return;
   405→          }
   406→          if (foundBackslash && pounds == poundsInARow) {
   407→            backup(pounds + 1);
   408→            isEscape = true;
   409→            return;
   410→          }
   411→        }
   412→        default -> {
   413→          quotesInARow = 0;
   414→          poundsInARow = 0;
   415→          foundBackslash = false;
   416→        }
   417→      }
   418→    }
   419→  }
   420→
   421→  private Token lexEscape() {
   422→    if (lookahead == EOF) throw unexpectedEndOfFile();
   423→    var ch = nextChar();
   424→    return switch (ch) {
   425→      case 'n' -> Token.STRING_ESCAPE_NEWLINE;
   426→      case '"' -> Token.STRING_ESCAPE_QUOTE;
   427→      case '\\' -> Token.STRING_ESCAPE_BACKSLASH;
   428→      case 't' -> Token.STRING_ESCAPE_TAB;
   429→      case 'r' -> Token.STRING_ESCAPE_RETURN;
   430→      case '(' -> {
   431→        var scope = interpolationStack.getFirst();
   432→        scope.parens++;
   433→        state = State.DEFAULT;
   434→        yield Token.INTERPOLATION_START;
   435→      }
   436→      case 'u' -> lexUnicodeEscape();
   437→      default ->
   438→          throw lexError(
   439→              ErrorMessages.create("invalidCharacterEscapeSequence", "\\" + ch, "\\"),
   440→              cursor - 2,
   441→              2);
   442→    };
   443→  }
   444→
   445→  private Token lexUnicodeEscape() {
   446→    if (lookahead != '{') {
   447→      throw unexpectedChar(lookahead, "{");
   448→    }
   449→    do {
   450→      nextChar();
   451→    } while (lookahead != '}' && lookahead != EOF && Character.isLetterOrDigit(lookahead));
   452→    if (lookahead == '}') {
   453→      // consume the close bracket
   454→      nextChar();
   455→    } else {
   456→      throw lexError(ErrorMessages.create("unterminatedUnicodeEscapeSequence", text()), span());
   457→    }
   458→    return Token.STRING_ESCAPE_UNICODE;
   459→  }
   460→
   461→  private Token lexIdentifier() {
   462→    while (isIdentifierPart(lookahead)) {
   463→      nextChar();
   464→    }
   465→
   466→    var identifierStr = text();
   467→    var identifier = getKeywordOrIdentifier(identifierStr);
   468→    return switch (identifier) {
   469→      case IMPORT -> {
   470→        if (lookahead == '*') {
   471→          nextChar();
   472→          yield Token.IMPORT_STAR;
   473→        } else yield Token.IMPORT;
   474→      }
   475→      case READ ->
   476→          switch (lookahead) {
   477→            case '*' -> {
   478→              nextChar();
   479→              yield Token.READ_STAR;
   480→            }
   481→            case '?' -> {
   482→              nextChar();
   483→              yield Token.READ_QUESTION;
   484→            }
   485→            default -> Token.READ;
   486→          };
   487→      default -> identifier;
   488→    };
   489→  }
   490→
   491→  private void lexQuotedIdentifier() {
   492→    while (lookahead != '`' && lookahead != '\n' && lookahead != '\r') {
   493→      nextChar();
   494→    }
   495→    if (lookahead == '`') {
   496→      nextChar();
   497→    } else {
   498→      throw unexpectedChar(lookahead, "backquote");
   499→    }
   500→  }
   501→
   502→  private Token lexNumber(char start) {
   503→    if (start == '0') {
   504→      if (lookahead == 'x' || lookahead == 'X') {
   505→        nextChar();
   506→        lexHexNumber();
   507→        return Token.HEX;
   508→      }
   509→      if (lookahead == 'b' || lookahead == 'B') {
   510→        nextChar();
   511→        lexBinNumber();
   512→        return Token.BIN;
   513→      }
   514→      if (lookahead == 'o' || lookahead == 'O') {
   515→        nextChar();
   516→        lexOctNumber();
   517→        return Token.OCT;
   518→      }
   519→      if (lookahead == 'e' || lookahead == 'E') {
   520→        nextChar();
   521→        lexExponent();
   522→        return Token.FLOAT;
   523→      }
   524→    } else if (start == '.') {
   525→      lexDotNumber();
   526→      return Token.FLOAT;
   527→    }
   528→
   529→    while ((lookahead >= 48 && lookahead <= 57) || lookahead == '_') {
   530→      nextChar();
   531→    }
   532→
   533→    if (lookahead == 'e' || lookahead == 'E') {
   534→      nextChar();
   535→      lexExponent();
   536→      return Token.FLOAT;
   537→    } else if (lookahead == '.') {
   538→      nextChar();
   539→      if (lookahead == '_') {
   540→        throw lexError("invalidSeparatorPosition");
   541→      }
   542→      if (lookahead < 48 || lookahead > 57) {
   543→        backup();
   544→        return Token.INT;
   545→      }
   546→      lexDotNumber();
   547→      return Token.FLOAT;
   548→    }
   549→    return Token.INT;
   550→  }
   551→
   552→  private Token lexSlash() {
   553→    switch (lookahead) {
   554→      case '/':
   555→        {
   556→          nextChar();
   557→          var token = lookahead == '/' ? Token.DOC_COMMENT : Token.LINE_COMMENT;
   558→          while (lookahead != '\n' && lookahead != '\r' && lookahead != EOF) {
   559→            nextChar();
   560→          }
   561→          return token;
   562→        }
   563→      case '*':
   564→        {
   565→          nextChar();
   566→          lexBlockComment();
   567→          return Token.BLOCK_COMMENT;
   568→        }
   569→      default:
   570→        return Token.DIV;
   571→    }
   572→  }
   573→
   574→  private void lexBlockComment() {
   575→    if (lookahead == EOF) throw unexpectedEndOfFile();
   576→    var prev = nextChar();
   577→    while (lookahead != EOF) {
   578→      if (prev == '*' && lookahead == '/') {
   579→        nextChar();
   580→        break;
   581→      }
   582→      prev = nextChar();
   583→    }
   584→    if (lookahead == EOF) throw unexpectedEndOfFile();
   585→  }
   586→
   587→  private void lexHexNumber() {
   588→    if (lookahead == '_') {
   589→      throw lexError("invalidSeparatorPosition");
   590→    }
   591→    if (!isHex(lookahead)) {
   592→      throw unexpectedChar(lookahead, "hexadecimal number");
   593→    }
   594→    while (isHex(lookahead) || lookahead == '_') {
   595→      nextChar();
   596→    }
   597→  }
   598→
   599→  private void lexBinNumber() {
   600→    if (lookahead == '_') {
   601→      throw lexError("invalidSeparatorPosition");
   602→    }
   603→    if (!(lookahead == '0' || lookahead == '1')) {
   604→      throw unexpectedChar(lookahead, "binary number");
   605→    }
   606→    while (lookahead == '0' || lookahead == '1' || lookahead == '_') {
   607→      nextChar();
   608→    }
   609→  }
   610→
   611→  private void lexOctNumber() {
   612→    if (lookahead == '_') {
   613→      throw lexError("invalidSeparatorPosition");
   614→    }
   615→    var ch = (int) lookahead;
   616→    if (!(ch >= 48 && ch <= 55)) {
   617→      throw unexpectedChar((char) ch, "octal number");
   618→    }
   619→    while ((ch >= 48 && ch <= 55) || ch == '_') {
   620→      nextChar();
   621→      ch = lookahead;
   622→    }
   623→  }
   624→
   625→  private void lexExponent() {
   626→    if (lookahead == '+' || lookahead == '-') {
   627→      nextChar();
   628→    }
   629→    if (lookahead == '_') {
   630→      throw lexError("invalidSeparatorPosition");
   631→    }
   632→    if (lookahead < 48 || lookahead > 57) {
   633→      throw unexpectedChar(lookahead, "number");
   634→    }
   635→    while ((lookahead >= 48 && lookahead <= 57) || lookahead == '_') {
   636→      nextChar();
   637→    }
   638→  }
   639→
   640→  private void lexDotNumber() {
   641→    if (lookahead == '_') {
   642→      throw lexError("invalidSeparatorPosition");
   643→    }
   644→    while ((lookahead >= 48 && lookahead <= 57) || lookahead == '_') {
   645→      nextChar();
   646→    }
   647→    if (lookahead == 'e' || lookahead == 'E') {
   648→      nextChar();
   649→      lexExponent();
   650→    }
   651→  }
   652→
   653→  private Token lexShebang() {
   654→    do {
   655→      nextChar();
   656→    } while (lookahead != '\n' && lookahead != '\r' && lookahead != EOF);
   657→    return Token.SHEBANG;
   658→  }
   659→
   660→  private boolean isHex(char ch) {
   661→    var code = (int) ch;
   662→    return (code >= 48 && code <= 57) || (code >= 97 && code <= 102) || (code >= 65 && code <= 70);
   663→  }
   664→
   665→  private static boolean isIdentifierStart(char c) {
   666→    return c == '_' || c == '$' || Character.isUnicodeIdentifierStart(c);
   667→  }
   668→
   669→  private static boolean isIdentifierPart(char c) {
   670→    return c != EOF && (c == '$' || Character.isUnicodeIdentifierPart(c));
   671→  }
   672→
   673→  private char nextChar() {
   674→    var tmp = lookahead;
   675→    cursor++;
   676→    if (cursor >= size) {
   677→      lookahead = EOF;
   678→    } else {
   679→      lookahead = source[cursor];
   680→    }
   681→    return tmp;
   682→  }
   683→
   684→  private void backup() {
   685→    lookahead = source[--cursor];
   686→  }
   687→
   688→  private void backup(int amount) {
   689→    cursor -= amount;
   690→    lookahead = source[cursor];
   691→  }
   692→
   693→  private ParserError lexError(String msg, Object... args) {
   694→    var length = lookahead == EOF ? 0 : 1;
   695→    var index = lookahead == EOF ? cursor - 1 : cursor;
   696→    return new ParserError(ErrorMessages.create(msg, args), new Span(index, length));
   697→  }
   698→
   699→  private ParserError lexError(String msg, int charIndex, int length) {
   700→    return new ParserError(msg, new Span(charIndex, length));
   701→  }
   702→
   703→  private ParserError lexError(String msg, Span span) {
   704→    return new ParserError(msg, span);
   705→  }
   706→
   707→  private ParserError unexpectedChar(char got, String didYouMean) {
   708→    return lexError("unexpectedCharacter", got, didYouMean);
   709→  }
   710→
   711→  private ParserError unexpectedChar(String got, String option1, String option2, String option3) {
   712→    return lexError("unexpectedCharacter3", got, option1, option2, option3);
   713→  }
   714→
   715→  private ParserError unexpectedEndOfFile() {
   716→    return lexError(ErrorMessages.create("unexpectedEndOfFile"), cursor, 0);
   717→  }
   718→
   719→  public static boolean isRegularIdentifier(String identifier) {
   720→    if (identifier.isEmpty()) return false;
   721→
   722→    if (isKeyword(identifier)) return false;
   723→
   724→    var firstCp = identifier.codePointAt(0);
   725→    return (firstCp == '$' || firstCp == '_' || Character.isUnicodeIdentifierStart(firstCp))
   726→        && identifier
   727→            .codePoints()
   728→            .skip(1)
   729→            .allMatch(cp -> cp == '$' || Character.isUnicodeIdentifierPart(cp));
   730→  }
   731→
   732→  public static String maybeQuoteIdentifier(String identifier) {
   733→    return isRegularIdentifier(identifier) ? identifier : "`" + identifier + "`";
   734→  }
   735→
   736→  private static boolean isKeyword(String text) {
   737→    return getKeywordOrIdentifier(text) != Token.IDENTIFIER;
   738→  }
   739→
   740→  private static Token getKeywordOrIdentifier(String keyword) {
   741→    return switch (keyword) {
   742→      case "_" -> Token.UNDERSCORE;
   743→      case "abstract" -> Token.ABSTRACT;
   744→      case "amends" -> Token.AMENDS;
   745→      case "as" -> Token.AS;
   746→      case "case" -> Token.CASE;
   747→      case "class" -> Token.CLASS;
   748→      case "const" -> Token.CONST;
   749→      case "delete" -> Token.DELETE;
   750→      case "else" -> Token.ELSE;
   751→      case "extends" -> Token.EXTENDS;
   752→      case "external" -> Token.EXTERNAL;
   753→      case "false" -> Token.FALSE;
   754→      case "fixed" -> Token.FIXED;
   755→      case "for" -> Token.FOR;
   756→      case "function" -> Token.FUNCTION;
   757→      case "hidden" -> Token.HIDDEN;
   758→      case "if" -> Token.IF;
   759→      case "import" -> Token.IMPORT;
   760→      case "in" -> Token.IN;
   761→      case "is" -> Token.IS;
   762→      case "let" -> Token.LET;
   763→      case "local" -> Token.LOCAL;
   764→      case "module" -> Token.MODULE;
   765→      case "new" -> Token.NEW;
   766→      case "nothing" -> Token.NOTHING;
   767→      case "null" -> Token.NULL;
   768→      case "open" -> Token.OPEN;
   769→      case "out" -> Token.OUT;
   770→      case "outer" -> Token.OUTER;
   771→      case "override" -> Token.OVERRIDE;
   772→      case "protected" -> Token.PROTECTED;
   773→      case "read" -> Token.READ;
   774→      case "record" -> Token.RECORD;
   775→      case "super" -> Token.SUPER;
   776→      case "switch" -> Token.SWITCH;
   777→      case "this" -> Token.THIS;
   778→      case "throw" -> Token.THROW;
   779→      case "trace" -> Token.TRACE;
   780→      case "true" -> Token.TRUE;
   781→      case "typealias" -> Token.TYPE_ALIAS;
   782→      case "unknown" -> Token.UNKNOWN;
   783→      case "vararg" -> Token.VARARG;
   784→      case "when" -> Token.WHEN;
   785→      default -> Token.IDENTIFIER;
   786→    };
   787→  }
   788→
   789→  private static class InterpolationScope {
   790→    final int quotes;
   791→    final int pounds;
   792→    int parens = 0;
   793→
   794→    protected InterpolationScope(int quotes, int pounds) {
   795→      this.quotes = quotes;
   796→      this.pounds = pounds;
   797→    }
   798→  }
   799→
   800→  private enum State {
   801→    DEFAULT,
   802→    STRING
   803→  }
   804→}
